"use client";
import { useState } from "react";
import {
  Field,
  FieldLabel,
  FieldError,
} from "@/components/ui/field";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useForm, Controller } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectTrigger,
  SelectContent,
  SelectItem,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { ImageUpload } from "@/lib/data/imageUpload";
import { toast, } from "sonner";
import { InsertProduct } from "@/lib/data/products";

export default function ProductForm({
  categories = [],
}: {
  categories: { id: number; name: string }[];
}) {
  const [isLoading, setIsLoading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  const formSchema = z.object({
    title: z.string().min(1, "This field is required"),
    price: z.coerce.number().min(1, "This field is required"),
    description: z.string().min(1, "This field is required"),
    category: z.string().min(1, "Please choose a category"),
    images: z
      .any()
      .refine((files) => files?.length > 0, "Please insert image here"),
  });

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: "",
      price: 0,
      description: "",
      category: "",
      images: null,
    },
  });

  async function onSubmit(values: z.infer<typeof formSchema>) {
    try {
      setIsLoading(true);

      const imageFormData = new FormData();
      imageFormData.append("file", values.images[0]);

      const uploadProduct = await ImageUpload(imageFormData);

      const productData = {
        title: values.title,
        price: values.price,
        description: values.description,
        categoryId: Number(values.category),
        images: [uploadProduct.location],
      };

      const data = await InsertProduct(productData);
      console.log(data);
      toast.success("Upload New Product Successfully.");
      form.reset();
    } catch (error) {
      toast.error("Failed to upload new product! Plz try again.");
    } finally {
      setIsLoading(false);
      setUploadProgress(0);
    }
  }

  function onReset() {
    form.reset();
    form.clearErrors();
  }

  return (
    <form
      onSubmit={form.handleSubmit(onSubmit)}
      onReset={onReset}
      className="space-y-8 pt-10"
    >
      <div className="grid grid-cols-12 gap-4">
        {/* title */}
        <Controller
          control={form.control}
          name="title"
          render={({ field, fieldState }) => (
            <Field className="col-span-12 flex flex-col gap-2">
              <FieldLabel>Product Name</FieldLabel>
              <Input
                placeholder="Macbook Pro 16"
                {...field}
                value={field.value ?? ""}
              />
              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} />
              )}
            </Field>
          )}
        />

        {/* price */}
        <Controller
          control={form.control}
          name="price"
          render={({ field, fieldState }) => (
            <Field className="col-span-12 flex flex-col gap-2">
              <FieldLabel>Price</FieldLabel>
              <Input
                type="number"
                placeholder="200 USD"
                {...field}
                value={field.value ?? 0}
              />
              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} />
              )}
            </Field>
          )}
        />

        {/* description */}
        <Controller
          control={form.control}
          name="description"
          render={({ field, fieldState }) => (
            <Field className="col-span-12 flex flex-col gap-2">
              <FieldLabel>Description</FieldLabel>
              <Textarea {...field} value={field.value ?? ""} />
              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} />
              )}
            </Field>
          )}
        />

        {/* category */}
        <Controller
          control={form.control}
          name="category"
          render={({ field, fieldState }) => (
            <Field className="col-span-12 flex flex-col gap-2">
              <FieldLabel>Category</FieldLabel>
              <Select
                value={field.value}
                onValueChange={field.onChange}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select category" />
                </SelectTrigger>
                <SelectContent>
                  {categories.map((c) => (
                    <SelectItem key={c.id} value={c.id.toString()}>
                      {c.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} />
              )}
            </Field>
          )}
        />

        {/* image */}
        <Controller
          control={form.control}
          name="images"
          render={({ field, fieldState }) => (
            <Field className="col-span-12 flex flex-col gap-2">
              <FieldLabel>Upload Image</FieldLabel>
              <Input
                type="file"
                onChange={(e) => field.onChange(e.target.files)}
              />
              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} />
              )}
            </Field>
          )}
        />

        {/* submit button */}
        <Field className="col-span-6 flex flex-col gap-2">
          <Button
            className="w-full"
            type="submit"
            variant="default"
            disabled={isLoading}
          >
            {isLoading
              ? `Uploading... ${Math.round(uploadProgress)}%`
              : "Submit"}
          </Button>
        </Field>

        {/* reset button */}
        <Field className="col-span-6 flex flex-col gap-2">
          <Button
            className="w-full"
            type="reset"
            variant="outline"
            disabled={isLoading}
          >
            Reset
          </Button>
        </Field>
      </div>
    </form>
  );
}